import {
  Component, input, output, inject,
  ChangeDetectionStrategy
} from '@angular/core';
import { ProductService } from './product.service';
import { CurrencyPipe } from '@angular/common';

interface Product { id: number; name: string; price: number; stock: number; }

// ════════════════════════════════════════════════════════
// DUMB component — no services, no side-effects
// Pure function of inputs. OnPush is safe.
// ════════════════════════════════════════════════════════
@Component({
  selector: 'app-product-card',
  standalone: true,
  imports: [CurrencyPipe],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div class="card">
      <h3>{{ product().name }}</h3>
      <p>{{ product().price | currency }}</p>
      <p>{{ product().stock }} in stock</p>
      <button
        [disabled]="product().stock === 0"
        (click)="addToCart.emit(product().id)"
      >
        Add to Cart
      </button>
    </div>
  `,
})
export class ProductCardComponent {
  product   = input.required<Product>();  // data flows IN
  addToCart = output<number>();           // events flow OUT
  // Nothing else — no inject(), no HTTP, no router
}


// ════════════════════════════════════════════════════════
// SMART component — owns the data, delegates rendering
// ════════════════════════════════════════════════════════
@Component({
  selector: 'app-product-list-page',
  standalone: true,
  imports: [ProductCardComponent],  // uses the dumb component
  template: `
    @if (loading()) {
      <p>Loading...</p>
    } @else {
      @for (p of products(); track p.id) {
        <app-product-card
          [product]="p"
          (addToCart)="onAddToCart($event)"
        />
      }
    }
  `,
})
export class ProductListPageComponent {
  private productService = inject(ProductService);  // knows about services

  products = this.productService.products;   // reads from service signal
  loading  = this.productService.loading;

  onAddToCart(id: number): void {
    this.productService.addToCart(id);  // delegates to service
  }
}

