import { Component, signal, Pipe, PipeTransform } from '@angular/core';

interface Product { id: number; name: string; price: number; category: string; }

// ── ✓ Pure Pipe — cached, called only when input changes ─────
@Pipe({ name: 'filterByCategory', standalone: true, pure: true })
export class FilterByCategoryPipe implements PipeTransform {
  transform(products: Product[], category: string): Product[] {
    console.log('pipe called'); // only logs when products or category changes
    if (!category) return products;
    return products.filter(p => p.category === category);
  }
}

@Pipe({ name: 'truncate', standalone: true, pure: true })
export class TruncatePipe implements PipeTransform {
  transform(text: string, maxLength = 100): string {
    return text.length > maxLength ? text.slice(0, maxLength) + '…' : text;
  }
}

@Component({
  selector: 'app-product-list',
  standalone: true,
  imports: [FilterByCategoryPipe, TruncatePipe],
  template: `
    <select [value]="selectedCategory()" (change)="selectedCategory.set($any($event.target).value)">
      <option value="">All</option>
      <option value="books">Books</option>
      <option value="tools">Tools</option>
    </select>

    <!-- ✗ WRONG: filterProducts() called on every CD cycle -->
    <!-- @for (p of filterProducts(); track p.id) { ... } -->

    <!-- ✓ CORRECT: pure pipe is cached, track prevents DOM churn -->
    @for (p of products() | filterByCategory:selectedCategory(); track p.id) {
      <div class="card">
        <h3>{{ p.name }}</h3>
        <!-- ✓ pipe for truncation — cached per unique input -->
        <p>{{ p.name | truncate:50 }}</p>
        <p>{{ p.price }}</p>
      </div>
    }

    <!-- ✓ track by id for objects, track $index only if items have no unique id -->
    @for (item of items(); track item.id) {
      <app-item [data]="item" />
    }
  `,
})
