import { signal, computed } from '@angular/core';

// ── ✓ Interface for data shapes (not class) ──────────────────
export interface User {
  readonly id:    string;
  readonly email: string;
  name:    string;
  role:    'admin' | 'editor' | 'viewer';  // string literal union
  address?: {                               // optional nested object
    city:    string;
    country: string;
  };
}

// ── ✗ AVOID: class for plain data
// class User { constructor(public id: string, public email: string) {} }


// ── ✓ Discriminated union — model async state properly ────────
type AsyncState<T> =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error';   message: string };

// TypeScript NARROWS the type in each branch — fully type-safe
function renderState<T>(state: AsyncState<T>): string {
  switch (state.status) {
    case 'loading': return 'Loading...';
    case 'success': return `Got ${JSON.stringify(state.data)}`; // data is T here
    case 'error':   return `Error: ${state.message}`;          // message is string here
    default:        return 'Idle';
  }
}

// ── ✓ Using discriminated union with Signals ─────────────────
const userState = signal<AsyncState<User>>({ status: 'idle' });

const isLoading = computed(() => userState().status === 'loading');
const userData  = computed(() =>
  userState().status === 'success' ? userState().data : null
);


