import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, of } from 'rxjs';
import { catchError } from 'rxjs/operators';

@Injectable({ providedIn: 'root' })
export class ApiService {
  private readonly http = inject(HttpClient); // readonly — communicates intent

  get<T>(url: string): Observable<T | null> {
    return this.http.get<T>(url).pipe(
      catchError(() => of(null))
    );
  }

  post<TBody, TResponse>(url: string, body: TBody): Observable<TResponse | null> {
    return this.http.post<TResponse>(url, body).pipe(
      catchError(() => of(null))
    );
  }
}
