import { Component, inject, input } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

@Component({
  selector: 'app-content',
  standalone: true,
  template: `
    <!-- ✓ Interpolation — always safe, HTML is escaped -->
    <p>{{ userInput() }}</p>
    <!-- If userInput is '<script>alert(1)</script>' it renders as text, not code -->

    <!-- ✓ [innerHTML] — Angular sanitises: removes scripts and event handlers -->
    <div [innerHTML]="sanitizedContent()"></div>

    <!-- ✗ DANGEROUS — only use when content comes from YOUR own trusted source -->
    <!-- <div [innerHTML]="trustedHtml"></div> where trustedHtml = bypassSecurity...() -->

    <!-- ✓ Safe: use bypassSecurityTrustHtml ONLY for your own SVG/HTML assets -->
    <div [innerHTML]="safeSvg"></div>
  `,
})
export class ContentComponent {
  private sanitizer = inject(DomSanitizer);

  userInput = input('');

  // Angular auto-sanitises [innerHTML] — removes <script>, onerror=, onclick= etc.
  sanitizedContent() {
    // Angular sanitises this automatically when bound with [innerHTML]
    return this.userInput(); // safe to use directly in [innerHTML]
  }

  // ✓ bypassSecurityTrust — ONLY for YOUR OWN trusted SVG/HTML content
  // NEVER pass user-provided strings here
  safeSvg: SafeHtml = this.sanitizer.bypassSecurityTrustHtml(
    '<svg viewBox="0 0 100 100"><circle cx="50" cy="50" r="40" fill="red"/></svg>'
  );
}


