import { Injectable, signal, computed, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { toSignal } from '@angular/core/rxjs-interop';
import { catchError, of } from 'rxjs';

interface Product { id: number; name: string; price: number; inStock: boolean; }

// ── ✓ Service: single responsibility — manages product state ──
@Injectable({ providedIn: 'root' })
export class ProductService {
  private readonly http = inject(HttpClient);

  // Descriptive, typed signals
  private _products   = signal<Product[]>([]);
  private _loading    = signal(false);
  private _selectedId = signal<number | null>(null);

  readonly products    = this._products.asReadonly();
  readonly loading     = this._loading.asReadonly();
  readonly inStockOnly = computed(() => this._products().filter(p => p.inStock));
  readonly selected    = computed(() =>
    this._products().find(p => p.id === this._selectedId()) ?? null
  );

  loadProducts(): void {
    this._loading.set(true);
    this.http.get<Product[]>('/api/products').pipe(
      catchError(() => of([]))
    ).subscribe(products => {
      this._products.set(products);
      this._loading.set(false);
    });
  }

  selectProduct(id: number): void  { this._selectedId.set(id); }
  clearSelection(): void           { this._selectedId.set(null); }

  // ── ✓ Early return — no deep nesting ───────────────────────
  updatePrice(id: number, newPrice: number): void {
    if (newPrice <= 0) return;           // guard clause — early return
    if (!this._products().length) return;

    this._products.update(list =>
      list.map(p => p.id === id ? { ...p, price: newPrice } : p)
    );
  }

  // ── ✓ Small, well-named private helpers ────────────────────
  private isValidPrice(price: number): boolean {
    return price > 0 && price < 100_000;
  }

  private findById(id: number): Product | undefined {
    return this._products().find(p => p.id === id);
  }
}
